import json
import re

# We've found that CALIFORNIA INST OF TECHN cited US-6237292-B1 (a UC patent)
# This is a citing assignee that is NOT UNIV CALIFORNIA
# Now let's find more citations systematically

# Load the non-UC patents dataset
other_file = locals().get('var_functions.query_db:32', '')
with open(other_file, 'r') as f:
    other_patents = json.load(f)

# Load UC patents to get their publication numbers
uc_file = locals().get('var_functions.query_db:5', '')
with open(uc_file, 'r') as f:
    uc_patents = json.load(f)

# Extract UC publication numbers
uc_pub_numbers = set()
for patent in uc_patents:
    patents_info = patent['Patents_info']
    # Extract all publication number patterns
    matches = re.findall(r'([A-Z]{2}-\d+[A-Z]?-\d+[A-Z]\d*)\.?\b', patents_info)
    for match in matches:
        uc_pub_numbers.add(match.rstrip('.'))

# Now search for citations to UC patents
citing_assignees = {}

for patent in other_patents:
    patents_info = patent['Patents_info']
    citation = patent.get('citation', '[]')
    cpc_codes = patent.get('cpc', '[]')

    if citation != '[]':
        try:
            citations = json.loads(citation.replace("'", '"'))

            for cite in citations:
                cited_patent = cite.get('publication_number', '')
                if cited_patent in uc_pub_numbers:
                    # Extract assignee
                    assignee_match = re.search(r'^(.+?)\s+(holds|is owned by|holds the|is assigned to)', patents_info)
                    if assignee_match:
                        assignee = assignee_match.group(1).strip()
                        if 'UNIV CALIFORNIA' not in assignee:
                            # Get CPC codes from the citing patent
                            cpc_list = []
                            if cpc_codes != '[]':
                                try:
                                    cpc_data = json.loads(cpc_codes.replace("'", '"'))
                                    for item in cpc_data:
                                        code = item.get('code', '')
                                        if code and code not in cpc_list:
                                            cpc_list.append(code)
                                except:
                                    pass

                            # Add to results
                            if assignee not in citing_assignees:
                                citing_assignees[assignee] = {
                                    'cited_uc_patents': [],
                                    'citing_cpc_codes': set()
                                }

                            citing_assignees[assignee]['cited_uc_patents'].append(cited_patent)
                            citing_assignees[assignee]['citing_cpc_codes'].update(cpc_list)
        except:
            continue

# Prepare results summary
final_results = []
for assignee, data in citing_assignees.items():
    final_results.append({
        'assignee': assignee,
        'cited_uc_patents': list(set(data['cited_uc_patents'])),
        'citing_cpc_codes': list(data['citing_cpc_codes'])
    })

print('__RESULT__:')
print(json.dumps({
    'uc_patents_analyzed': len(uc_pub_numbers),
    'other_patents_analyzed': len(other_patents),
    'citing_assignees_found': len(final_results),
    'sample_results': final_results[:5]
}, indent=2))

