import json
import re

# Load all data
uc_file = locals().get('var_functions.query_db:5', '')
other_file = locals().get('var_functions.query_db:32', '')

try:
    with open(uc_file, 'r') as f:
        uc_patents = json.load(f)
    with open(other_file, 'r') as f:
        other_patents = json.load(f)
except:
    print('__RESULT__:')
    print(json.dumps('Error loading files'))
    exit()

# Extract all UC publication numbers
uc_pub_numbers = set()
for patent in uc_patents:
    words = patent['Patents_info'].split()
    for word in words:
        clean_word = word.strip('.,;:!?')
        if re.match(r'^[A-Z]{2}-\d{4,}-[A-Z]\d*$', clean_word):
            uc_pub_numbers.add(clean_word)

print('UC patents found:', len(uc_pub_numbers))

# Search for citations systematically
citation_results = []

# Limit to a reasonable number of patents to search
search_limit = min(len(other_patents), 500)

for idx, patent in enumerate(other_patents[:search_limit]):
    patents_info = patent['Patents_info']
    citation = patent.get('citation', '[]')
    cpc = patent.get('cpc', '[]')

    if citation == '[]':
        continue

    try:
        # Parse citations
        citations = json.loads(citation.replace("'", '"'))

        for cite in citations:
            cited_patent = cite.get('publication_number', '')
            if cited_patent in uc_pub_numbers:
                # Extract assignee
                assignee_match = re.search(r'^(.+?)\s+(holds|is owned by|holds the|is assigned to|owns)', patents_info)
                if assignee_match:
                    assignee = assignee_match.group(1).strip()
                    if 'UNIV CALIFORNIA' not in assignee:
                        # Extract unique primary CPC subclasses (before /)
                        cpc_codes = []
                        if cpc != '[]':
                            try:
                                cpc_list = json.loads(cpc.replace("'", '"'))
                                for item in cpc_list:
                                    full_code = item.get('code', '')
                                    if full_code:
                                        primary = full_code.split('/')[0]
                                        if primary not in cpc_codes:
                                            cpc_codes.append(primary)
                            except:
                                pass

                        citation_results.append({
                            'assignee': assignee,
                            'cited_uc_patent': cited_patent,
                            'citing_cpc_subclasses': cpc_codes
                        })
    except Exception as e:
        continue

print('Citations found:', len(citation_results))

# Group by assignee
assignee_groups = {}
for result in citation_results:
    assignee = result['assignee']
    if assignee not in assignee_groups:
        assignee_groups[assignee] = {
            'cited_uc_patents': set(),
            'cpc_subclasses': set()
        }
    assignee_groups[assignee]['cited_uc_patents'].add(result['cited_uc_patent'])
    assignee_groups[assignee]['cpc_subclasses'].update(result['citing_cpc_subclasses'])

print('Assignees found:', len(assignee_groups))

# Get all unique CPC subclasses to look up
cpc_subclasses = set()
for data in assignee_groups.values():
    cpc_subclasses.update(data['cpc_subclasses'])

result = {
    'assignees_count': len(assignee_groups),
    'cpc_subclasses_to_lookup': sorted(list(cpc_subclasses)),
    'sample_assignees': list(assignee_groups.keys())[:10]
}

print('CPC subclasses to lookup:', len(cpc_subclasses))

print('__RESULT__:')
print(json.dumps(result, indent=2))

